let rawData = $input.item.json;

// If rawData.query is a JSON string, parse it
if (typeof rawData?.query === "string") {
  const s = rawData.query.trim();
  if (s.startsWith("{") && s.endsWith("}")) {
    try {
      rawData = JSON.parse(s);
    } catch (e) {
      return [{
        json: {
          _validation_error: true,
          email: "",
          chatId: null,
          error_message: "Invalid JSON in query field",
          parse_error: e.message,
        }
      }];
    }
  }
}

// Handle nested 'base' object or flat structure
const data = rawData.base || rawData;

// Validate required fields
if (!data.email || !data.userQuery) {
  return [{
    json: {
      _validation_error: true,
      email: data.email || '',
      chatId: data.chatId || null,
      error_message: 'Missing required fields: email or userQuery',
      _debug: { keys: Object.keys(rawData) }
    }
  }];
}

// Normalize with fallbacks
return [{
  json: {
    email: data.email,
    chatId: data.chatId || null,
    userQuery: data.userQuery,
    intent: String(data.intent || 'unknown').toLowerCase(),
    confidence: Number(data.confidence ?? 0.8),
    userLanguage: data.userLanguage || "Unknown",
    timestamp: data.timestamp || new Date().toISOString(),
    _original: {
      had_base: !!rawData.base,
      top_level_keys: Object.keys(rawData)
    }
  }
}];

const input = $input.item.json;

return [{
  json: {
    email: input.email,
    chatId: input.chatId,
    answerText: "Missing required information. Please provide email and userQuery.",
    confidenceScore: 0.0,
    responseTimestamp: new Date().toISOString(),
    suggestedQueries: []
  }
}];

// Return as array for parent workflow
const output = $input.item.json;

return [{
  json: [output]
}];

