const input = $('Build Query by Intent').item.json;
const dbResults = $input.all().map(item => item.json);

let contextData = '';

// Check if any data returned
if (!dbResults || dbResults.length === 0 || !dbResults[0].first_name) {
  return [{
    json: {
      ...input,
      contextData: 'No data found',
      firstName: 'there',
      hasData: false
    }
  }];
}

const firstName = dbResults[0].first_name;
const currency = dbResults[0].currency;

// Format data based on intent
switch(input.intent) {
  case 'check_balance':
    const balance = dbResults[0];
    contextData = `Balance: ${currency} ${parseFloat(balance.total_balance || 0).toFixed(2)}, Properties: ${balance.properties_count}, Next due: ${balance.next_due_date || 'N/A'}`;
    break;

  case 'due_date':
    const dueDate = dbResults[0];
    contextData = `Next payment due: ${dueDate.next_due_date || 'N/A'}, Amount: ${currency} ${parseFloat(dueDate.amount_due || 0).toFixed(2)}`;
    break;

  case 'payment_history':
    // Aggregate all payment records
    const totalPaid = dbResults.reduce((sum, p) => sum + parseFloat(p.payment_amount || 0), 0);
    const paymentList = dbResults.map((p, i) => 
      `${i+1}. ${p.payment_date.split('T')[0]}: ${currency} ${parseFloat(p.payment_amount).toFixed(2)} via ${p.payment_mode} (Receipt: ${p.receipt_number})`
    ).join(', ');
    contextData = `Last ${dbResults.length} payments (Total: ${currency} ${totalPaid.toFixed(2)}): ${paymentList}`;
    break;

  case 'total_owed':
    const total = dbResults[0];
    contextData = `Total owed: ${currency} ${parseFloat(total.total_owed || 0).toFixed(2)} across ${total.properties_count} properties`;
    break;

  default:
    contextData = `DB results for ${firstName}:` + JSON.stringify(dbResults[0]);
}

return [{
  json: {
    ...input,
    contextData: contextData,
    firstName: firstName,
    hasData: true
  }
}];

