const input = $('Aggregate Payment Data').first().json;
const groqResponse = $input.first().json;

const raw = String(groqResponse?.choices?.[0]?.message?.content ?? "").trim();
const finishReason = groqResponse?.choices?.[0]?.finish_reason;

// Defaults
let answerText = "Request processed.";
let translatedRatepayerResponse = "Request processed.";
let nativeLanguageName = input.userLanguage || "Unknown";

// Try strict JSON parse first
function tryParseJson(text) {
  const start = text.indexOf("{");
  const end = text.lastIndexOf("}");
  if (start === -1 || end === -1 || end <= start) return null;
  try {
    return JSON.parse(text.slice(start, end + 1));
  } catch {
    return null;
  }
}

let parsed = tryParseJson(raw);

if (parsed && typeof parsed === "object") {
  answerText = String(parsed.answerText ?? answerText).trim() || answerText;
  translatedRatepayerResponse =
    String(parsed.translated_ratepayer_response ?? "").trim() || translatedRatepayerResponse;

  // optional if you added it in prompt
  if (parsed.native_language_name) {
    nativeLanguageName = String(parsed.native_language_name).trim() || nativeLanguageName;
  }
} else {
  // JSON is missing/truncated. Salvage values if possible.
  // This works even when finish_reason = "length"
  const m1 = raw.match(/"answerText"\s*:\s*"([\s\S]*?)"\s*,\s*"translated_ratepayer_response"/);
  if (m1?.[1]) answerText = m1[1].replace(/\\"/g, '"').trim() || answerText;

  const m2 = raw.match(/"translated_ratepayer_response"\s*:\s*"([\s\S]*)$/);
  if (m2?.[1]) {
    // Remove trailing unfinished JSON garbage if present
    translatedRatepayerResponse = m2[1]
      .replace(/\\"/g, '"')
      .replace(/"\s*[,}]*\s*$/g, "")
      .trim() || translatedRatepayerResponse;
  }
}

// Suggested queries by intent (keep your mapping, but your intent keys are inconsistent)
const suggestions = {
  ratepayer_lookup: ["When is my next payment due?", "Show me my payment history"],
  get_due_date: ["What is my current balance?", "Show me my payment history"],
  payment_history: ["What is my current balance?", "When is my next payment due?"],
  total_owed: ["Show me my payment history", "When is my next payment due?"],
};

const intentKey = String(input.intent ?? "").trim();

return [{
  json: {
    email: input.email,
    chatId: input.chatId,
    answerText,
    translatedRatepayerResponse,        // ✅ new field
    nativeLanguageName,                // ✅ optional, if you want
    confidenceScore: Number(input.confidence ?? 0),
    responseTimestamp: new Date().toISOString(),
    suggestedQueries: suggestions[intentKey] || ["What is my current balance?", "When is my next payment due?"],
    finishReason,                      // ✅ debug (remove later)
  }
}];
